var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"침식체 머리통이 하나~ 침식체 머리통이 둘~","JPN":"侵食体の頭ひと～つ、侵食体の頭ふた～つ……","ENG":"That's a C.O.'s head, and that's another one.","TWN":"一個侵蝕體腦袋瓜～兩個侵蝕體腦袋瓜～"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아이쿠, 얘는 머리가 실하게 익었네. 우량아인가 봐.","JPN":"あらあら、この子は頭がずいぶんデカいね。健康優良児ってやつ？","ENG":"Whoa, this one's got a real big head. Maybe it used to eat a lot.","TWN":"哎呀呀，這傢伙的腦袋長得可真大。看來是個健康寶寶呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"눈에 뭐라도 들어갔어? 아까부터 계속 인상 찌푸리고 있네?","JPN":"目にゴミでも入った？　さっきから眉間にしわが寄ってるけど？","ENG":"Do you have something in your eyes? Why are you frowning?","TWN":"有什麼東西了跑進妳眼睛裡了嗎？妳從剛才開始皺著眉頭耶？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"......노려보는 거예요.","JPN":"……睨んでいるのです。","ENG":"I'm staring.","TWN":"……我是在瞪人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"왜? 아직 살아 있는 침식체라도 있어? 어디어디?","JPN":"何で？　まだ生きてる侵食体でもいた？　どこどこ？","ENG":"At what? Do you see a living C.O. anywhere? Where is it?","TWN":"為什麼？還有活著的侵蝕體嗎？哪裡哪裡？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"침식체가 아니라 당신이요! 당신을 노려보고 있는 거라고요!","JPN":"侵食体ではなく、あなたです！　あなたを睨んでいるのです！","ENG":"I'm talking about you! I've been staring at you!","TWN":"不是瞪侵蝕體，是在瞪妳！我是在瞪著妳！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"에이, 돈 떼먹힐까 봐 불안해?","JPN":"もしかして、報酬を独り占めされるのが心配？","ENG":"Come on, you're worried that I'd keep all the money to myself, aren't you?","TWN":"噢，擔心我把錢私吞了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"이래 봬도 계산은 확실히 한다구. 사냥 수당 받으면 네 몫은 제대로 나눠 줄게.","JPN":"こう見えても、計算はしっかりする主義なんだよね。報酬をもらったら、アンタの分はちゃんと分けるから。","ENG":"I'm a fair person and a sincere partner. You'll get your share when they pay me for these heads.","TWN":"別看我這樣，我會好好算帳的。拿到狩獵津貼的話，妳那一份會好好分給妳的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"아, 그래요?","JPN":"ああ、そうですか。","ENG":"Oh, really?","TWN":"啊，是嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"관리국도 신경 끄는 곳인데 수당이 어디서 나오나요?","JPN":"でも、管理局にも見放された場所なのに、報酬はどこから出るのです？","ENG":"And who's going to pay you? The Administration doesn't even know about this place.","TWN":"這裡連管理局都沒心去管了，去哪裡拿津貼啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"그야 맥크레디 가문의 금고에서 나오겠지? 날 고용한 사람이 학회장이니까.","JPN":"そりゃ、マクレディー家の金庫からでしょ。アタシを雇ったのは学会長だし。","ENG":"The MacCready family, I guess? I was employed by the President of the Society herself.","TWN":"那當然是從麥克蕾蒂家的金庫裡拿呀？畢竟雇用我的人是學會長。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"네? 저희 가문의 자산과 학회장이 대체 무슨 상관이죠?","JPN":"え？　マクレディー家の資産と学会長に何の関係が？","ENG":"Huh? What's the President doing with my family's assets?","TWN":"咦？我家族的財產和學會長到底有什麼關係？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"아, 레지나는 모르겠구나.","JPN":"ああ、レジーナは知らないんだね。","ENG":"Ah, you haven't heard, I guess.","TWN":"啊，蕾佳娜不知道啊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"네가 없는 동안 맥크레디 가문은 학회장이 대신 관리하고 있었어.","JPN":"アンタがいない間、マクレディー家は学会長が代わりに管理してるんだよ。","ENG":"The President has been taking care of the MacCready family while you were gone.","TWN":"妳不在的時候，麥克蕾蒂家族是由學會長代為管理的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"하......!","JPN":"えっ……！","ENG":"Ha!","TWN":"啥……！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그 에델이란 작자, 후견인 행세를 하면서 남의 집안 재산을 자기 지갑처럼 쓰나 보군요.","JPN":"そのエデルという方が……後見人として振る舞いながら、よその家の財産を自分の財布のように使っているのですね。","ENG":"This Edel wench must be spending the family money like water, pretending to be the guardian.","TWN":"看來那個叫艾瑟兒的傢伙，裝作監護人的樣子，一邊把別人家的財產當自己的錢包用呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어떻게 감히......","JPN":"それも、我がマクレディー家の……","ENG":"How dare she!","TWN":"她竟敢……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"리벳, 어서 길을 안내하세요. 서둘러야겠습니다.","JPN":"リベット、案内してください。急がなければなりません。","ENG":"Lead the way, Rivet. We have to hurry.","TWN":"里維，快點帶路吧，我趕時間。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"왜? 느긋하게 가야 침식체도 더 많이 만날 텐데?","JPN":"何で？　ゆっくり行った方が侵食体をいっぱい倒せると思うけど？","ENG":"And why is that? We won't be able to encounter as many C.O.s that way.","TWN":"為什麼？慢慢走才能遇到更多侵蝕體啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"어머니가 돌아가신 지금, 맥크레디 가문의 정당한 주인은 다른 누구도 아닌 접니다.","JPN":"お母様が亡くなった今、マクレディー家の正当な主は他の誰でもなく、この私です。","ENG":"Now that my mother has passed, the rightful heir of the MacCready family is none other than me.","TWN":"現在我的母親已經去世了，麥克蕾蒂家族的正當所有者不是其他任何人，而是我。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그런데 제게 한마디 없이 저택에 눌러앉아 선조들이 쌓아 올린 가산을 멋대로 쓰고 있다니요?","JPN":"それなのに、断りもなく邸宅に居座って\\n先祖代々受け継がれてきた財産を勝手に使っているのですよ？","ENG":"And this person has been spending the fortune accumulated by my ancestors without my knowledge?","TWN":"但是她竟然一句話都沒跟我說，就安坐在宅邸，隨意使用我祖先積攢下來的家產？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"이건 저희 가문을 우롱하는 처사입니다.","JPN":"これは我がマクレディー家への冒涜に他なりませんわ。","ENG":"This is outright ridiculous!","TWN":"這是愚弄我們家族的行為。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"가만두지 않겠어요. 그 잘난 낯짝이 얼마나 두꺼울지 기대되네요.","JPN":"絶対に許しません。どれだけ偉そうにしていても、化けの皮をはがしてやらなければ。","ENG":"I won't forgive her. I can't wait to see how thick-skinned she is!","TWN":"我不會輕易放過她的。她那張嘴臉，臉皮是能有多厚，還真令人期待呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"우와, 설마 학회장 얼굴가죽이라도 벗기게?","JPN":"うわー、もしかして学会長の面の皮でも剝ぐつもり？","ENG":"Woah, you're going to deskin her?","TWN":"嗚哇，難道是要把學會長的臉皮扒下來嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"맥크레디 집안의 필수 교양이 제물 손질이라더니 역시......","JPN":"マクレディー家の必須教養は生贄の下処理だって聞いてたけど……","ENG":"So it was true that the MacCready kids grow up learning how to prep their sacrifices.","TWN":"麥克蕾蒂家族的必修教養竟然是修理祭品啊……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그게 무슨 야만적인 발상이에요?! 그냥 쫓아내겠다는 소리죠!","JPN":"野蛮な発想はおやめください！！　ただ追い出すだけですわ！","ENG":"What kind of barbaric thinking is that? I'm just saying I'm going to kick her out!","TWN":"妳這是什麼野蠻的發想啊？！我只說要把她趕出去而已！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L33_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"애초에 제물 따위를 바쳤다는 소문도 우리 집안을 시기한 자들의 음해일 뿐이에요.","JPN":"そもそも、生贄を捧げたという噂もマクレディー家を妬む者たちが流したデマに過ぎません。","ENG":"And sacrificing is just another rumor that the jealous spread to undermine the reputation of the family.","TWN":"而且那些獻祭之類的傳聞，也都是嫉妒我們家族的人在惡意中傷而已。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"그러니 그런 헛소문은 두 번 다시 제 앞에서 들먹이지 마세요. 매우 불쾌하니까요.","JPN":"ですから、もう二度と私の前でそのようなくだらない噂話は出さないでいただけませんか？　不愉快極まりない話ですわ。","ENG":"Please do not speak that disgusting nonsense in front of me ever again. Do you know how offensive it is to me?","TWN":"所以，請不要再次在我面前提起這種荒謬的傳聞，這非常令人不愉快。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"REGINA_ESPR_NULL_NULL","text":{"KOREA":"자! 알아들었으면 어서 안내나 하시죠! 갈 길이 멉니다!","JPN":"さあ！　分かっていただけたならば、案内してください！　まだ先は長いですわ！","ENG":"Now, if you understand me, lead the way. We have a long way to go.","TWN":"好了！既然聽明白了，就快點帶路吧！還有很多路要走呢！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REGINA_ESPR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"RIVET_ESPR_NULL_NULL","text":{"KOREA":"네이, 네이. 제가 알아 모셔야죠.","JPN":"はいはい。ご案内しますよ。","ENG":"Yeah, yeah. As you wish, my lady.","TWN":"好，好。畢竟我得好好伺候妳嘛。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};